import { getHeroesBySearchCriteria } from '../../services/hero.service'
import { getProbabilityThatHeroesCanSummonTargetGene } from '../../helpers/genes.helpers'
import { PascalCase, ToPrice } from '../../helpers/format.helpers'

export const sortAndFilterHeroes = (heroes, filters, sortBy, mutationClass) => {
    let sortedHeroes = heroes

    // Skip filtering and sorting if there are no records
    if (!heroes.length) return sortedHeroes

    const summonClass = PascalCase(mutationClass)

    // Filter based on filter criteria
    sortedHeroes = sortedHeroes.filter(hero => {
        const remainingSummons = !filters.summonsRemaining || Number(hero.summonsRemaining) >= Number(filters.summonsRemaining)
        const maxSummons = !filters.maxSummons || Number(hero.maxSummons) >= Number(filters.maxSummons)
        const minGen = !filters.minGen || filters.minGen === '' || Number(hero.generation) >= Number(filters.minGen)
        const maxGen = !filters.maxGen || filters.maxGen === '' || Number(hero.generation) <= Number(filters.maxGen)
        const mainClass = filters.includeSummonClass || hero.mainClass !== summonClass
        const classMatch = !filters.classMatch || hero.mainClassGenes[0] === hero.mainClassGenes[1]
        const subclassMatch = !filters.subclassMatch || hero.subClassGenes[0] === hero.subClassGenes[1]
        const professionMatch = !filters.professionMatch || hero.professionGenes[0] === hero.professionGenes[1]

        return maxSummons &&
            remainingSummons &&
            minGen &&
            maxGen &&
            mainClass &&
            classMatch &&
            subclassMatch &&
            professionMatch
    })

    // Sort heroes by probability or price
    switch (sortBy) {
        case 'probability':
            return sortedHeroes.sort(sortByProbability)
        case 'price':
            return sortedHeroes.sort(sortByPrice)
        default:
            return sortedHeroes
    }
}

const sortByProbability = (a, b) => {
    return a.targetProbability > b.targetProbability ?
        -1 :
        a.targetProbability < b.targetProbability ? 1 : 0
}

const sortByPrice = (a, b) => {
    const aPrice = a.price + (a.auctionType === 'sale' ? 0 : a.summonCost)
    const bPrice = b.price + (b.auctionType === 'sale' ? 0 : b.summonCost)
    return aPrice > bPrice ? 1 : aPrice < bPrice ? -1 : 0
}

// Retrieve a page of matching heroes from the Tavern and return the ones that match
export const getSummoningProbability = async (mainHero, options, pageSize, offset) => {
    const listedHeroes = await getHeroesBySearchCriteria(options, pageSize, offset)

    // Analyze each of the heroes in auction
    for (let i = 0; i < listedHeroes.length; i++) {
        const heroToAnalyze = listedHeroes[i]
        heroToAnalyze.auctionType = options.auctionType
        heroToAnalyze.price = ToPrice(heroToAnalyze.price)

        let classProbability = 1
        let subclassProbability = 1
        let professionProbability = 1

        // Apply the mainclass probability, if applicable
        {
            const a = getProbabilityThatHeroesCanSummonTargetGene(mainHero.mainClassGenes, heroToAnalyze.mainClassGenes, options.summonClass)
            classProbability = a ? a.value : 0
        }

        // Apply the subclass probability, if applicable
        if (options.summonSubclass !== 'all') {
            const b = getProbabilityThatHeroesCanSummonTargetGene(mainHero.subClassGenes, heroToAnalyze.subClassGenes, options.summonSubclass)
            subclassProbability = b ? b.value : 0
        }

        // Apply the profession probability, if applicable
        if (options.profession !== 'all') {
            const c = getProbabilityThatHeroesCanSummonTargetGene(mainHero.professionGenes, heroToAnalyze.professionGenes, options.profession)
            professionProbability = c ? c.value : 0
        }

        heroToAnalyze.targetProbability = classProbability * subclassProbability * professionProbability
    }

    // Remove any heroes who cannot be used to summon the target class
    const filteredHeroes = listedHeroes.filter(hero => hero.targetProbability > 0)

    return [filteredHeroes, listedHeroes.length]
}