import React, { useState } from 'react'
import PropTypes from 'prop-types'
import CheckboxWithLabel from '../CheckboxWithLabel'
import FormControlsGroup from '../FormControlsGroup'
import Grid from '@mui/material/Grid'
import MenuItem from '@mui/material/MenuItem'
import SortSelecter from '../SortSelecter'
import Switch from '@mui/material/Switch'
import TextboxWithLabel from '../TextboxWithLabel'
import './SortFilter.css'

const SortFilter = ({ filters, onFilterChange, onSortByChange, onViewToggled }) => {
    const [sortBy, setSort] = useState('probability')

    const handleFilterChange = ({ target }) => {
        switch (target.name) {
            case 'summonsRemaining':
            case 'maxSummons':
            case 'minGen':
            case 'maxGen':
                onFilterChange({ key: target.name, value: target.value })
                break;

            case 'classMatch':
            case 'subclassMatch':
            case 'professionMatch':
            case 'includeSummonClass':
            case 'includeAllHeroes':
                onFilterChange({ key: target.name, value: target.checked })
                break;

            default:
                console.log('unknown search filter selected')
        }
    }


    const handleViewToggled = (event) => {
        onViewToggled(event.target.checked)
    }


    const handleSortByChange = ({ target }) => {
        setSort(target.value)
        onSortByChange(target.value)
    }

    return (
        <Grid container className='sort-filter'>
            <Grid item className='section'>
                <Switch defaultChecked={false} onChange={handleViewToggled} />
                Flip Cards
            </Grid>
            <Grid item className='section'>
                <SortSelecter name='sort-by' value={sortBy} onChange={handleSortByChange}>
                    <MenuItem key='probability' value='probability'>Probability</MenuItem>
                    <MenuItem key='price' value='price'>Price</MenuItem>
                </SortSelecter>
            </Grid>
            <Grid item className='section'>
                <div className='filter-label'>
                    Filters:
                </div>
                <FormControlsGroup title='Summons'>
                    <TextboxWithLabel label='Remaining' name='summonsRemaining' value={filters.summonsRemaining} onChange={handleFilterChange} />
                    <TextboxWithLabel label='Max' name='maxSummons' value={filters.maxSummons} onChange={handleFilterChange} />
                </FormControlsGroup>
                <FormControlsGroup title='Generation'>
                    <TextboxWithLabel label='Min' name='minGen' value={filters.minGen} onChange={handleFilterChange} />
                    <TextboxWithLabel label='Max' name='maxGen' value={filters.maxGen} onChange={handleFilterChange} />
                </FormControlsGroup>
                <FormControlsGroup title='D/R1 Gene Match' className='extra-margin'>
                    <CheckboxWithLabel label='Class' name='classMatch' value={filters.classMatch} onChange={handleFilterChange} />
                    <CheckboxWithLabel label='Subclass' name='subclassMatch' value={filters.subclassMatch} onChange={handleFilterChange} />
                    <CheckboxWithLabel label='Profession' name='professionMatch' value={filters.professionMatch} onChange={handleFilterChange} />
                </FormControlsGroup>
                <FormControlsGroup title='Include' className='extra-margin'>
                    <CheckboxWithLabel label='Summon Class' name='includeSummonClass' value={filters.includeSummonClass} onChange={handleFilterChange} />
                    {/* <CheckboxWithLabel label='All Heroes' name='includeAllHeroes' value={filters.includeAllHeroes} onChange={handleFilterChange} /> */}
                </FormControlsGroup>
            </Grid>
        </Grid>
    )
}

SortFilter.propTypes = {
    filters: PropTypes.object,
    onFilterChange: PropTypes.func,
    onSortByChange: PropTypes.func,
    onViewToggled: PropTypes.func
}

SortFilter.defaultProps = {
    filters: { },
    onFilterChange: () => { },
    onSortByChange: () => { },
    onViewToggled: () => { }
}

export default SortFilter
